import play.api._
import play.api.mvc._
import slick.jdbc.JdbcProfile
import models.products._ // assuming you have a Product model in this file and it has columns id, name etc... 
// replace with your actual product table fields if they are different  

class SearchController(db: JdbcProfile) extends Controller {
    
    def searchProducts = Action.async { implicit request =>
        val params : Map[String, String] = request.queryString().asJson.map(json2Map(_)) // convert query string into map 
        
       if (params.isEmpty){  
          return Future.successful(BadRequest("Missing parameters"))   
      }    
          
        val categoryId : Option[Int] = params.get("category_id") map { Integer.parseInt(_) } // get the optional int from query string 
        
       if(!params.contains("priceFrom" ) || !(params.get("priceTo").map{Integer.parseInt(_)}.isValid)){  
          return Future.successful(BadRequest("Missing parameters"))   
      }    
        // create the where clause based on query string params 
       val condition = categoryId match {        
            case Some(id) => Products.category === id          
             _ =>  (Products.price >= params["priceFrom"].toDouble && Products.price <=params["priceTo"].toDouble)}      // check if there is a price range provided 
        whereCondition : condition*  
         val products = db.run(sql"SELECT * FROM products WHERE $whereCondition".as[Product].list())   
          .map(products => Ok(Json.prettyPrint(products)))    
       return products      //return the list of product in json format 
        }                 
}